import type BuildingFilterModeSolid from "./BuildingFilterModeSolid.js";
import type BuildingFilterModeWireFrame from "./BuildingFilterModeWireFrame.js";
import type BuildingFilterModeXRay from "./BuildingFilterModeXRay.js";
import type { JSONSupport } from "../../core/JSONSupport.js";
import type { BuildingFilterModeXRayProperties } from "./BuildingFilterModeXRay.js";
import type { BuildingFilterModeWireFrameProperties } from "./BuildingFilterModeWireFrame.js";
import type { BuildingFilterModeSolidProperties } from "./BuildingFilterModeSolid.js";

/** @since 5.0 */
export interface BuildingFilterBlockProperties extends Partial<Pick<BuildingFilterBlock, "filterExpression" | "title">> {
  /**
   * Defines how features are drawn while the filter is active.
   *
   * @since 5.0
   */
  filterMode?: (BuildingFilterModeSolidProperties & { type: "solid" }) | (BuildingFilterModeWireFrameProperties & { type: "wire-frame" }) | (BuildingFilterModeXRayProperties & { type: "x-ray" });
}

/**
 * Object contained in the [BuildingFilter.filterBlocks](https://developers.arcgis.com/javascript/latest/references/core/layers/support/BuildingFilter/#filterBlocks) collection:
 *
 * @since 5.0
 */
export default class BuildingFilterBlock extends JSONSupport {
  constructor(properties?: BuildingFilterBlockProperties);
  /**
   * The SQL where clause used to match features to this filter block.
   *                                       Only the features that satisfy the filter expression are displayed in the [SceneView](https://developers.arcgis.com/javascript/latest/references/core/views/SceneView/).
   *                                       This property is evaluated on the client using the cached attributes and it only supports
   *                                       [standardized SQL](https://doc.arcgis.com/en/arcgis-online/reference/sql-agol.htm).
   *
   * @since 5.0
   */
  accessor filterExpression: string | null;
  /**
   * Defines how features are drawn while the filter is active.
   *
   * @since 5.0
   */
  get filterMode(): BuildingFilterModeSolid | BuildingFilterModeWireFrame | BuildingFilterModeXRay;
  set filterMode(value: (BuildingFilterModeSolidProperties & { type: "solid" }) | (BuildingFilterModeWireFrameProperties & { type: "wire-frame" }) | (BuildingFilterModeXRayProperties & { type: "x-ray" }));
  /**
   * Title of the filter for display in UIs, for example when the filter block is edited in ArcGIS Pro.
   *
   * @default ""
   * @since 5.0
   */
  accessor title: string;
}